import React, { useState, useEffect, useRef, useMemo } from 'react';

const theme = {
  colors: {
    primary: '#8b5cf6',
    background: '#0a0a0a',
    surface: '#111111',
    surfaceAlt: '#1a1a1a',
    border: '#2a2a2a',
    text: '#fafafa',
    textSecondary: '#a1a1aa',
    textMuted: '#52525b',
    blue: '#38bdf8',
    yellow: '#fbbf24',
    pink: '#f472b6',
    green: '#a3e635',
    orange: '#fb923c',
  },
  font: "'JetBrains Mono', monospace",
};

const initialLr = 0.1;
const tMax = 20;
const minLr = 0.001;
const halfRange = 0.5 * (initialLr - minLr);

const getLr = (e) => {
  const c = Math.min(Math.max(e, 0), tMax);
  return minLr + halfRange * (1 + Math.cos((c / tMax) * Math.PI));
};

const getLinearLr = (e) => {
  const c = Math.min(Math.max(e, 0), tMax);
  return initialLr - (initialLr - minLr) * (c / tMax);
};

export default function App() {
  const [epoch, setEpoch] = useState(0);
  const [showLinear, setShowLinear] = useState(false);
  const [playing, setPlaying] = useState(false);
  const [dragging, setDragging] = useState(false);
  const svgRef = useRef(null);

  const currentLr = getLr(epoch);
  const currentLinearLr = getLinearLr(epoch);

  const W = 540, H = 230;
  const pad = { l: 52, r: 16, t: 16, b: 32 };
  const pW = W - pad.l - pad.r;
  const pH = H - pad.t - pad.b;
  const yMax = initialLr * 1.1;

  const toSvgX = (e) => pad.l + (e / tMax) * pW;
  const toSvgY = (lr) => pad.t + pH * (1 - lr / yMax);
  const fromSvgX = (px) => (px - pad.l) / pW * tMax;

  const cosineCurvePath = useMemo(() => {
    const pts = [];
    for (let i = 0; i <= 200; i++) {
      const e = (i / 200) * tMax;
      const prefix = i === 0 ? 'M' : 'L';
      pts.push(prefix + toSvgX(e).toFixed(1) + ',' + toSvgY(getLr(e)).toFixed(1));
    }
    return pts.join('');
  }, []);

  const cosineFilledPath = useMemo(() => {
    if (epoch <= 0) return '';
    const steps = Math.max(20, epoch * 10);
    const pts = [];
    for (let i = 0; i <= steps; i++) {
      const e = (i / steps) * epoch;
      const prefix = i === 0 ? 'M' : 'L';
      pts.push(prefix + toSvgX(e).toFixed(1) + ',' + toSvgY(getLr(e)).toFixed(1));
    }
    pts.push('L' + toSvgX(epoch).toFixed(1) + ',' + toSvgY(0).toFixed(1));
    pts.push('L' + toSvgX(0).toFixed(1) + ',' + toSvgY(0).toFixed(1));
    pts.push('Z');
    return pts.join('');
  }, [epoch]);

  const handleInteraction = (e) => {
    const svg = svgRef.current;
    if (!svg) return;
    const rect = svg.getBoundingClientRect();
    const px = ((e.clientX - rect.left) / rect.width) * W;
    const ep = fromSvgX(px);
    const clamped = Math.max(0, Math.min(tMax, Math.round(ep)));
    setEpoch(clamped);
  };

  useEffect(() => {
    if (!playing) return;
    const interval = setInterval(() => {
      setEpoch((prev) => {
        if (prev >= tMax) {
          setPlaying(false);
          return tMax;
        }
        return prev + 1;
      });
    }, 280);
    return () => clearInterval(interval);
  }, [playing]);

  useEffect(() => {
    const up = () => setDragging(false);
    window.addEventListener('mouseup', up);
    return () => window.removeEventListener('mouseup', up);
  }, []);

  const handleReset = () => {
    setPlaying(false);
    setEpoch(0);
    setShowLinear(false);
  };

  const handlePlay = () => {
    if (epoch >= tMax) setEpoch(0);
    setPlaying(!playing);
  };

  const progress = epoch / tMax;
  const cosVal = Math.cos((epoch / tMax) * Math.PI);

  const getInsight = () => {
    const base = (() => {
      if (epoch === 0) return 'Starting at maximum LR. Large steps let the model quickly explore the loss landscape.';
      if (epoch === tMax) return 'Reached minimum LR. Tiny updates allow precise fine-tuning near the optimum.';
      if (progress < 0.25) return 'Early training: cosine decays gently, keeping LR high for broad exploration.';
      if (progress < 0.5) return 'LR dropping more steeply now. Cosine accelerates the shift from exploration to refinement.';
      if (progress < 0.75) return 'Past midpoint: rapid decay through moderate LRs as the model zeroes in on good regions.';
      return 'Approaching minimum: cosine flattens, allowing gentle fine-tuning near convergence.';
    })();
    if (showLinear && epoch > 0 && epoch < tMax) {
      const diff = currentLr - currentLinearLr;
      if (Math.abs(diff) < 0.0005) return base + ' Cosine and linear are nearly equal at this point.';
      if (diff > 0) return base + ' Cosine LR is ' + diff.toFixed(4) + ' HIGHER than linear here - more time exploring.';
      return base + ' Cosine LR is ' + Math.abs(diff).toFixed(4) + ' LOWER than linear - refining more aggressively.';
    }
    return base;
  };

  const yTicks = [0, 0.02, 0.04, 0.06, 0.08, 0.10];
  const xTicks = [0, 5, 10, 15, 20];

  const btnStyle = (active, color) => ({
    padding: '5px 12px',
    background: active ? color : 'transparent',
    border: '1px solid ' + color,
    borderRadius: '6px',
    color: active ? '#000' : color,
    fontFamily: theme.font,
    fontSize: '11px',
    fontWeight: '600',
    cursor: 'pointer',
    transition: 'all 0.2s ease',
  });

  return (
    <div style={{ background: theme.colors.background, minHeight: '100vh', padding: '16px', fontFamily: theme.font, color: theme.colors.text }}>
      <div style={{ maxWidth: 600, margin: '0 auto' }}>

        {/* Header */}
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '12px' }}>
          <div>
            <div style={{ fontSize: '18px', fontWeight: '700' }}>Cosine Annealing LR</div>
            <div style={{ fontSize: '11px', color: theme.colors.textSecondary, marginTop: '2px' }}>
              Click or drag the chart to set epoch. Watch the LR follow a cosine curve.
            </div>
          </div>
          <div style={{ display: 'flex', gap: '6px', alignItems: 'center' }}>
            <button onClick={handlePlay} style={btnStyle(playing, theme.colors.green)}>
              {playing ? 'Pause' : 'Play'}
            </button>
            <button onClick={handleReset} style={btnStyle(false, theme.colors.textSecondary)}>Reset</button>
          </div>
        </div>

        {/* Epoch + LR display */}
        <div style={{ display: 'flex', gap: '16px', alignItems: 'baseline', marginBottom: '10px' }}>
          <div style={{ fontSize: '28px', fontWeight: '800', color: theme.colors.blue, transition: 'all 0.15s ease' }}>
            {currentLr.toFixed(4)}
          </div>
          <div style={{ fontSize: '13px', color: theme.colors.textSecondary }}>
            at epoch <span style={{ color: theme.colors.primary, fontWeight: '700', fontSize: '15px' }}>{epoch}</span> / {tMax}
          </div>
          {showLinear && (
            <div style={{ fontSize: '13px', color: theme.colors.orange, marginLeft: 'auto' }}>
              Linear: {currentLinearLr.toFixed(4)}
            </div>
          )}
        </div>

        {/* Main Chart */}
        <div style={{ background: theme.colors.surface, borderRadius: '10px', border: '1px solid ' + theme.colors.border, padding: '8px 4px 4px 4px', marginBottom: '10px' }}>
          <svg
            ref={svgRef}
            viewBox={'0 0 ' + W + ' ' + H}
            style={{ width: '100%', display: 'block', cursor: dragging ? 'grabbing' : 'crosshair', userSelect: 'none' }}
            onMouseDown={(e) => { setDragging(true); setPlaying(false); handleInteraction(e); }}
            onMouseMove={(e) => { if (dragging) handleInteraction(e); }}
            onMouseUp={() => setDragging(false)}
            onMouseLeave={() => setDragging(false)}
          >
            {/* Grid lines */}
            {yTicks.map((y) => (
              <line key={'gy' + y} x1={pad.l} y1={toSvgY(y)} x2={W - pad.r} y2={toSvgY(y)}
                stroke={theme.colors.border} strokeWidth="0.5" />
            ))}
            {xTicks.map((x) => (
              <line key={'gx' + x} x1={toSvgX(x)} y1={pad.t} x2={toSvgX(x)} y2={H - pad.b}
                stroke={theme.colors.border} strokeWidth="0.5" />
            ))}

            {/* Y-axis labels */}
            {yTicks.map((y) => (
              <text key={'ly' + y} x={pad.l - 6} y={toSvgY(y) + 1} textAnchor="end" dominantBaseline="middle"
                fontSize="9" fill={theme.colors.textSecondary} fontFamily={theme.font}>
                {y.toFixed(2)}
              </text>
            ))}

            {/* X-axis labels */}
            {xTicks.map((x) => (
              <text key={'lx' + x} x={toSvgX(x)} y={H - pad.b + 15} textAnchor="middle"
                fontSize="9" fill={theme.colors.textSecondary} fontFamily={theme.font}>
                {x}
              </text>
            ))}

            {/* Axis titles */}
            <text x={W / 2} y={H - 2} textAnchor="middle" fontSize="10" fill={theme.colors.textMuted} fontFamily={theme.font}>
              Epoch
            </text>
            <text x={13} y={H / 2} textAnchor="middle" fontSize="10" fill={theme.colors.textMuted} fontFamily={theme.font}
              transform={'rotate(-90, 13, ' + (H / 2) + ')'}>
              Learning Rate
            </text>

            {/* Filled area under cosine curve up to current epoch */}
            {epoch > 0 && (
              <path d={cosineFilledPath} fill={theme.colors.blue} opacity="0.1" />
            )}

            {/* Linear comparison line */}
            {showLinear && (
              <line x1={toSvgX(0)} y1={toSvgY(initialLr)} x2={toSvgX(tMax)} y2={toSvgY(minLr)}
                stroke={theme.colors.orange} strokeWidth="2" strokeDasharray="6,4" opacity="0.6" />
            )}

            {/* Full cosine curve */}
            <path d={cosineCurvePath} fill="none" stroke={theme.colors.blue} strokeWidth="2.5" opacity="0.35" />

            {/* Highlighted curve up to current epoch */}
            {epoch > 0 && (() => {
              const pts = [];
              const steps = Math.max(20, epoch * 10);
              for (let i = 0; i <= steps; i++) {
                const e = (i / steps) * epoch;
                const prefix = i === 0 ? 'M' : 'L';
                pts.push(prefix + toSvgX(e).toFixed(1) + ',' + toSvgY(getLr(e)).toFixed(1));
              }
              return <path d={pts.join('')} fill="none" stroke={theme.colors.blue} strokeWidth="2.5" />;
            })()}

            {/* Epoch dots on curve */}
            {Array.from({ length: tMax + 1 }, (_, i) => i).map((e) => {
              const isActive = e <= epoch;
              const isCurrent = e === epoch;
              if (isCurrent) return null;
              return (
                <circle key={'dot' + e} cx={toSvgX(e)} cy={toSvgY(getLr(e))} r={2}
                  fill={isActive ? theme.colors.blue : theme.colors.border}
                  opacity={isActive ? 0.7 : 0.4} />
              );
            })}

            {/* Linear comparison dot */}
            {showLinear && (
              <circle cx={toSvgX(epoch)} cy={toSvgY(currentLinearLr)} r={5}
                fill={theme.colors.orange} stroke="#000" strokeWidth="1.5" />
            )}

            {/* Vertical dashed line at current epoch */}
            <line x1={toSvgX(epoch)} y1={toSvgY(currentLr) + 9} x2={toSvgX(epoch)} y2={toSvgY(0)}
              stroke={theme.colors.primary} strokeWidth="1" strokeDasharray="3,3" opacity="0.4" />

            {/* Current epoch marker - main interactive dot */}
            <circle cx={toSvgX(epoch)} cy={toSvgY(currentLr)} r="8"
              fill={theme.colors.blue} stroke={theme.colors.text} strokeWidth="2" />

            {/* Glow effect */}
            <circle cx={toSvgX(epoch)} cy={toSvgY(currentLr)} r="14"
              fill="none" stroke={theme.colors.blue} strokeWidth="1" opacity="0.25" />

            {/* min_lr reference line */}
            <line x1={pad.l} y1={toSvgY(minLr)} x2={W - pad.r} y2={toSvgY(minLr)}
              stroke={theme.colors.green} strokeWidth="1" strokeDasharray="2,4" opacity="0.3" />
            <text x={W - pad.r + 2} y={toSvgY(minLr) + 1} fontSize="8" fill={theme.colors.green} fontFamily={theme.font}
              dominantBaseline="middle" opacity="0.6">min</text>

            {/* initial_lr reference line */}
            <line x1={pad.l} y1={toSvgY(initialLr)} x2={W - pad.r} y2={toSvgY(initialLr)}
              stroke={theme.colors.pink} strokeWidth="1" strokeDasharray="2,4" opacity="0.3" />
            <text x={W - pad.r + 2} y={toSvgY(initialLr) + 1} fontSize="8" fill={theme.colors.pink} fontFamily={theme.font}
              dominantBaseline="middle" opacity="0.6">max</text>
          </svg>
        </div>

        {/* Formula computation */}
        <div style={{ background: theme.colors.surface, borderRadius: '8px', border: '1px solid ' + theme.colors.border, padding: '10px 14px', marginBottom: '10px', fontSize: '11px', lineHeight: 1.8 }}>
          <div style={{ color: theme.colors.textSecondary }}>
            <span style={{ color: theme.colors.textMuted }}>LR = </span>
            <span style={{ color: theme.colors.green }}>{minLr}</span>
            <span style={{ color: theme.colors.textMuted }}> + 0.5 * (</span>
            <span style={{ color: theme.colors.pink }}>{initialLr}</span>
            <span style={{ color: theme.colors.textMuted }}> - </span>
            <span style={{ color: theme.colors.green }}>{minLr}</span>
            <span style={{ color: theme.colors.textMuted }}>) * (1 + cos(</span>
            <span style={{ color: theme.colors.primary }}>{epoch}</span>
            <span style={{ color: theme.colors.textMuted }}>/</span>
            <span style={{ color: theme.colors.textSecondary }}>{tMax}</span>
            <span style={{ color: theme.colors.textMuted }}> * pi))</span>
          </div>
          <div>
            <span style={{ color: theme.colors.textMuted }}>   = {minLr} + {halfRange.toFixed(4)} * (1 + </span>
            <span style={{ color: theme.colors.yellow }}>{cosVal.toFixed(4)}</span>
            <span style={{ color: theme.colors.textMuted }}>) = </span>
            <span style={{ color: theme.colors.blue, fontWeight: '700', fontSize: '13px' }}>{currentLr.toFixed(4)}</span>
          </div>
        </div>

        {/* Compare toggle */}
        <div style={{ display: 'flex', gap: '10px', alignItems: 'center', marginBottom: '10px' }}>
          <button onClick={() => setShowLinear(!showLinear)} style={btnStyle(showLinear, theme.colors.orange)}>
            {showLinear ? 'Hide' : 'Compare:'} Linear Decay
          </button>
          {showLinear && (
            <span style={{ fontSize: '11px', color: theme.colors.orange, opacity: 0.8 }}>
              Dashed line = constant rate of decay
            </span>
          )}
        </div>

        {/* Insight */}
        <div style={{
          background: theme.colors.surfaceAlt, borderRadius: '8px', padding: '10px 14px',
          fontSize: '11px', color: theme.colors.textSecondary, lineHeight: 1.6,
          borderLeft: '3px solid ' + theme.colors.primary, transition: 'all 0.3s ease',
        }}>
          <span style={{ color: theme.colors.primary, fontWeight: '600' }}>Insight: </span>
          {getInsight()}
        </div>

        {/* Epoch progress bar */}
        <div style={{ marginTop: '12px' }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: '10px', color: theme.colors.textMuted, marginBottom: '4px' }}>
            <span>Epoch 0</span>
            <span style={{ color: theme.colors.textSecondary, fontSize: '11px' }}>Drag below or click chart above</span>
            <span>Epoch {tMax}</span>
          </div>
          <div
            style={{ position: 'relative', height: '28px', background: theme.colors.surface, borderRadius: '14px', border: '1px solid ' + theme.colors.border, cursor: 'pointer', overflow: 'hidden' }}
            onClick={(e) => {
              const rect = e.currentTarget.getBoundingClientRect();
              const frac = (e.clientX - rect.left) / rect.width;
              setEpoch(Math.max(0, Math.min(tMax, Math.round(frac * tMax))));
              setPlaying(false);
            }}
          >
            <div style={{
              position: 'absolute', left: 0, top: 0, bottom: 0,
              width: (epoch / tMax * 100) + '%',
              background: 'linear-gradient(90deg, ' + theme.colors.blue + '33, ' + theme.colors.primary + '55)',
              borderRadius: '14px',
              transition: dragging ? 'none' : 'width 0.15s ease',
            }} />
            <div style={{
              position: 'absolute',
              left: 'calc(' + (epoch / tMax * 100) + '% - 14px)',
              top: '0px',
              width: '28px', height: '28px',
              borderRadius: '50%',
              background: theme.colors.blue,
              border: '2px solid ' + theme.colors.text,
              display: 'flex', alignItems: 'center', justifyContent: 'center',
              fontSize: '9px', fontWeight: '700', color: '#000',
              transition: dragging ? 'none' : 'left 0.15s ease',
              boxShadow: '0 0 8px ' + theme.colors.blue + '66',
            }}>
              {epoch}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

